-- {"operators": "OUTER_JOIN,AGGREGATE,WINDOW,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER", "ducklake": true}
WITH combined AS (SELECT c.C_W_ID, c.C_ID, c.C_LAST, o.O_ID, o.O_ENTRY_D FROM dl.CUSTOMER c LEFT JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID) SELECT C_W_ID, C_ID, C_LAST, COUNT(O_ID) OVER (PARTITION BY C_W_ID) AS w_orders, O_ID FROM combined;
